import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  DASHBOARD = 'DASHBOARD',
  MAP_DRAWING = 'MAP_DRAWING',
  EXCAVATION_PLANNING = 'EXCAVATION_PLANNING',
  ARTIFACT_ILLUSTRATION = 'ARTIFACT_ILLUSTRATION',
  AI_STUDIO = 'AI_STUDIO', // Includes 3D, Text-to-Image, Image Editing
  TRANSLATION = 'TRANSLATION'
}

export enum AIJobType {
  TEXT_TO_IMAGE = 'TEXT_TO_IMAGE',
  IMAGE_EDITING = 'IMAGE_EDITING',
  RECONSTRUCTION_3D = 'RECONSTRUCTION_3D'
}

export interface DrawingTool {
  name: string;
  icon: string;
  lineWidth: number;
  color: string;
}

export interface LogEntry {
  id: string;
  timestamp: Date;
  message: string;
  type: 'info' | 'success' | 'error';
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// Helper to convert base64 to standard clean base64 if needed (stripping headers)
const cleanBase64 = (dataUrl: string) => {
  return dataUrl.split(',')[1] || dataUrl;
};

// Text to Image Generation (using gemini-2.5-flash-image which supports generation via prompt)
export const generateImageFromText = async (prompt: string): Promise<string> => {
  try {
    const ai = getAIClient();
    // Using gemini-2.5-flash-image for generation/editing
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      }
    });

    // Check for inline data (image) or text logic
    const parts = response.candidates?.[0]?.content?.parts;
    if (parts) {
      for (const part of parts) {
        if (part.inlineData) {
            return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("No image generated.");
  } catch (error) {
    console.error("Generate Image Error:", error);
    throw error;
  }
};

// Image Editing (Nano Banana feature)
export const editImageWithPrompt = async (base64Image: string, prompt: string): Promise<string> => {
  try {
    const ai = getAIClient();
    const cleanData = cleanBase64(base64Image);

    // According to Gemini guidelines, we can send image + text to edit/generate
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/png', // Assuming PNG from canvas/upload, adjust if needed
              data: cleanData
            }
          },
          { text: prompt }
        ]
      }
    });

    const parts = response.candidates?.[0]?.content?.parts;
    if (parts) {
      for (const part of parts) {
        if (part.inlineData) {
            return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
        }
      }
    }
    throw new Error("No edited image returned.");
  } catch (error) {
    console.error("Edit Image Error:", error);
    throw error;
  }
};

// Translation
export const translateDescription = async (text: string, targetLanguage: string): Promise<string> => {
  try {
    const ai = getAIClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Translate the following archaeological description into ${targetLanguage}. Keep the tone academic and precise.\n\n"${text}"`
    });
    return response.text || "Translation failed.";
  } catch (error) {
    console.error("Translation Error:", error);
    return "Error during translation.";
  }
};

// Analyze Voice Command
export const analyzeVoiceCommand = async (transcript: string): Promise<{ action: string, details: string }> => {
  try {
    const ai = getAIClient();
    const prompt = `
      Analyze this voice command from an archaeological app user: "${transcript}".
      Map it to one of these actions: 'NAVIGATE_MAP', 'NAVIGATE_PLAN', 'NAVIGATE_ARTIFACT', 'NAVIGATE_AI', 'NAVIGATE_TRANSLATE', 'UNKNOWN'.
      Return ONLY a JSON object: {"action": "...", "details": "optional context"}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: { responseMimeType: 'application/json' }
    });

    const text = response.text;
    if (text) {
      return JSON.parse(text);
    }
    return { action: 'UNKNOWN', details: '' };
  } catch (error) {
    console.error("Voice Analysis Error:", error);
    return { action: 'UNKNOWN', details: '' };
  }
};

import React, { useRef, useState, useEffect } from 'react';
import { DrawingTool, AppMode } from '../types';

interface WorkBenchProps {
  mode: AppMode;
}

const WorkBench: React.FC<WorkBenchProps> = ({ mode }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [context, setContext] = useState<CanvasRenderingContext2D | null>(null);

  // Tool State
  const [color, setColor] = useState('#2b2b2b');
  const [lineWidth, setLineWidth] = useState(2);
  const [showGrid, setShowGrid] = useState(mode === AppMode.EXCAVATION_PLANNING);

  useEffect(() => {
    if (canvasRef.current) {
      const canvas = canvasRef.current;
      // High DPI fix
      const dpr = window.devicePixelRatio || 1;
      const rect = canvas.getBoundingClientRect();

      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;

      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.scale(dpr, dpr);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        setContext(ctx);

        // Initial Background
        ctx.fillStyle = '#fdfbf7';
        ctx.fillRect(0, 0, rect.width, rect.height);

        if (showGrid) drawGrid(ctx, rect.width, rect.height);
      }
    }
  }, [mode, showGrid]);

  useEffect(() => {
    setShowGrid(mode === AppMode.EXCAVATION_PLANNING);
  }, [mode]);

  const drawGrid = (ctx: CanvasRenderingContext2D, w: number, h: number) => {
    ctx.strokeStyle = '#e6dec8';
    ctx.lineWidth = 1;
    const step = 40;

    ctx.beginPath();
    for (let x = 0; x <= w; x += step) {
      ctx.moveTo(x, 0);
      ctx.lineTo(x, h);
    }
    for (let y = 0; y <= h; y += step) {
      ctx.moveTo(0, y);
      ctx.lineTo(w, y);
    }
    ctx.stroke();
  };

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!context) return;
    setIsDrawing(true);
    const { offsetX, offsetY } = e.nativeEvent;
    context.beginPath();
    context.moveTo(offsetX, offsetY);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || !context) return;
    const { offsetX, offsetY } = e.nativeEvent;

    context.strokeStyle = color;
    context.lineWidth = lineWidth;
    context.lineTo(offsetX, offsetY);
    context.stroke();
  };

  const stopDrawing = () => {
    if (!context) return;
    context.closePath();
    setIsDrawing(false);
  };

  const clearCanvas = () => {
    if (!context || !canvasRef.current) return;
    const canvas = canvasRef.current;
    // Clearing resets the pixel ratio transform, so we fill rect logic
    context.clearRect(0, 0, canvas.width, canvas.height); // Logical coords might be off if not careful
    // Safest simple clear
    const rect = canvas.getBoundingClientRect();
    context.fillStyle = '#fdfbf7';
    context.fillRect(0, 0, rect.width, rect.height);
    if (showGrid) drawGrid(context, rect.width, rect.height);
  };

  const downloadDrawing = () => {
    if (canvasRef.current) {
      const link = document.createElement('a');
      link.download = `hatice-ceylan-${mode.toLowerCase()}-${Date.now()}.png`;
      link.href = canvasRef.current.toDataURL();
      link.click();
    }
  };

  return (
    <div className="flex flex-col h-full w-full bg-arch-paper relative shadow-inner">
      {/* Toolbar */}
      <div className="absolute top-4 left-4 z-10 flex flex-col gap-2 bg-white/90 backdrop-blur p-3 rounded-lg border border-arch-clay shadow-sm">
        <label className="text-xs font-serif font-bold text-arch-dark uppercase mb-1">Tools</label>

        <div className="flex gap-2 mb-2">
          <button 
            onClick={() => setColor('#2b2b2b')} 
            className={`w-6 h-6 rounded-full border border-gray-300 ${color === '#2b2b2b' ? 'ring-2 ring-arch-clay' : ''}`}
            style={{ backgroundColor: '#2b2b2b' }}
          />
          <button 
            onClick={() => setColor('#a67c52')} 
            className={`w-6 h-6 rounded-full border border-gray-300 ${color === '#a67c52' ? 'ring-2 ring-arch-clay' : ''}`}
            style={{ backgroundColor: '#a67c52' }}
          />
          <button 
            onClick={() => setColor('#b91c1c')} 
            className={`w-6 h-6 rounded-full border border-gray-300 ${color === '#b91c1c' ? 'ring-2 ring-arch-clay' : ''}`}
            style={{ backgroundColor: '#b91c1c' }}
          />
        </div>

        <div className="flex flex-col gap-1">
          <label className="text-[10px] text-arch-dark">Line Width</label>
          <input 
            type="range" 
            min="1" 
            max="10" 
            value={lineWidth} 
            onChange={(e) => setLineWidth(Number(e.target.value))}
            className="w-24 accent-arch-clay" 
          />
        </div>

        <div className="h-px bg-arch-sand my-1"></div>

        <button 
          onClick={() => setShowGrid(!showGrid)}
          className="text-xs flex items-center gap-2 hover:text-arch-clay transition-colors"
        >
          <span className="font-bold">#</span> Toggle Grid
        </button>

        <button 
          onClick={clearCanvas}
          className="text-xs flex items-center gap-2 text-red-700 hover:text-red-900 transition-colors mt-2"
        >
          <span>✕</span> Clear Page
        </button>

        <button 
          onClick={downloadDrawing}
          className="text-xs flex items-center gap-2 text-arch-clay hover:text-arch-dark transition-colors mt-1 font-bold"
        >
          <span>↓</span> Download
        </button>
      </div>

      {/* Canvas Area */}
      <div className="flex-1 overflow-hidden p-8 cursor-crosshair">
         <div className="w-full h-full bg-white shadow-lg border border-arch-sand relative">
            <canvas
              ref={canvasRef}
              className="w-full h-full block"
              onMouseDown={startDrawing}
              onMouseMove={draw}
              onMouseUp={stopDrawing}
              onMouseLeave={stopDrawing}
            />

            {/* Corner Label */}
            <div className="absolute bottom-4 right-4 text-arch-clay font-hand text-2xl opacity-50 select-none pointer-events-none">
              {mode === AppMode.MAP_DRAWING ? 'Harita / Map' : 
               mode === AppMode.EXCAVATION_PLANNING ? 'Plan / Plan' : 
               'Buluntu / Artifact'}
            </div>
         </div>
      </div>
    </div>
  );
};

export default WorkBench;

import React, { useState } from 'react';
import { AIJobType } from '../types';
import { generateImageFromText, editImageWithPrompt, translateDescription } from '../services/geminiService';

const AIStudio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AIJobType>(AIJobType.IMAGE_EDITING);
  const [inputText, setInputText] = useState('');
  const [sourceImage, setSourceImage] = useState<string | null>(null);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [translationResult, setTranslationResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSourceImage(reader.result as string);
        setResultImage(null); // Clear previous result
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAction = async () => {
    setLoading(true);
    setError('');
    try {
      if (activeTab === AIJobType.TEXT_TO_IMAGE) {
        if (!inputText) throw new Error("Please enter a description.");
        const img = await generateImageFromText(inputText);
        setResultImage(img);
      } 
      else if (activeTab === AIJobType.IMAGE_EDITING) {
        if (!sourceImage) throw new Error("Please upload an image first.");
        if (!inputText) throw new Error("Please describe the edit (e.g., 'remove background').");
        const img = await editImageWithPrompt(sourceImage, inputText);
        setResultImage(img);
      }
      else if (activeTab === AIJobType.RECONSTRUCTION_3D) {
         if (!sourceImage) throw new Error("Please upload a 2D sketch.");
         // Simulation: We use the edit API to ask for a "3D render style"
         const prompt = "Transform this 2D archaeological sketch into a photorealistic 3D render on a neutral studio background. High detail, ambient occlusion.";
         const img = await editImageWithPrompt(sourceImage, prompt);
         setResultImage(img);
      }
    } catch (err: any) {
      setError(err.message || "An error occurred.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex h-full w-full bg-arch-paper p-6 gap-6">

      {/* Sidebar Controls */}
      <div className="w-1/3 flex flex-col gap-6">
        <div className="bg-white p-4 rounded-lg border border-arch-clay shadow-sm">
          <h2 className="text-xl font-serif text-arch-dark mb-4 border-b border-arch-sand pb-2">
            AI Studio
          </h2>

          <div className="flex flex-col gap-2 mb-6">
            <button 
              onClick={() => { setActiveTab(AIJobType.IMAGE_EDITING); setError(''); }}
              className={`p-3 text-left rounded-md transition-all ${activeTab === AIJobType.IMAGE_EDITING ? 'bg-arch-clay text-white' : 'hover:bg-arch-sand text-arch-dark'}`}
            >
              <div className="font-bold">✎ Smart Edit (Nano Banana)</div>
              <div className="text-xs opacity-80">Edit images with natural language</div>
            </button>

            <button 
              onClick={() => { setActiveTab(AIJobType.TEXT_TO_IMAGE); setError(''); }}
              className={`p-3 text-left rounded-md transition-all ${activeTab === AIJobType.TEXT_TO_IMAGE ? 'bg-arch-clay text-white' : 'hover:bg-arch-sand text-arch-dark'}`}
            >
              <div className="font-bold">✨ Text to Image</div>
              <div className="text-xs opacity-80">Generate visuals from descriptions</div>
            </button>

            <button 
              onClick={() => { setActiveTab(AIJobType.RECONSTRUCTION_3D); setError(''); }}
              className={`p-3 text-left rounded-md transition-all ${activeTab === AIJobType.RECONSTRUCTION_3D ? 'bg-arch-clay text-white' : 'hover:bg-arch-sand text-arch-dark'}`}
            >
              <div className="font-bold">🧊 3D Reconstruction</div>
              <div className="text-xs opacity-80">Convert 2D sketches to 3D visuals</div>
            </button>
          </div>

          <div className="space-y-4">
            {/* Image Upload Input - Only if needed */}
            {(activeTab !== AIJobType.TEXT_TO_IMAGE) && (
              <div>
                <label className="block text-sm font-bold text-arch-dark mb-1">Source Image</label>
                <div className="relative border-2 border-dashed border-arch-clay/50 rounded-lg p-4 text-center hover:bg-arch-sand/20 transition-colors">
                  <input 
                    type="file" 
                    accept="image/*"
                    onChange={handleImageUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                  {sourceImage ? (
                    <span className="text-green-700 text-sm font-bold">Image Loaded ✓</span>
                  ) : (
                    <span className="text-arch-dark text-sm">Click to Upload or Drop Image</span>
                  )}
                </div>
              </div>
            )}

            {/* Text Input */}
            <div>
              <label className="block text-sm font-bold text-arch-dark mb-1">
                {activeTab === AIJobType.IMAGE_EDITING ? 'Edit Instruction' : 
                 activeTab === AIJobType.TEXT_TO_IMAGE ? 'Visual Description' : 'Notes (Optional)'}
              </label>
              <textarea 
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                placeholder={
                  activeTab === AIJobType.IMAGE_EDITING ? "e.g., Remove the background, Add a vintage filter..." : 
                  activeTab === AIJobType.TEXT_TO_IMAGE ? "e.g., Ancient Roman amphora with detailed handles..." : 
                  "Optional notes..."
                }
                className="w-full p-3 rounded border border-arch-clay bg-white focus:ring-2 focus:ring-arch-clay focus:outline-none min-h-[100px] font-sans"
              />
            </div>

            <button
              onClick={handleAction}
              disabled={loading}
              className={`w-full py-3 rounded text-white font-bold tracking-wider uppercase transition-all
                ${loading ? 'bg-gray-400 cursor-not-allowed' : 'bg-arch-dark hover:bg-black shadow-lg'}
              `}
            >
              {loading ? 'Processing with Gemini...' : 'Generate'}
            </button>

            {error && (
              <div className="p-3 bg-red-100 border border-red-300 text-red-800 text-sm rounded">
                {error}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Preview Area */}
      <div className="w-2/3 bg-white border border-arch-sand rounded-lg p-6 shadow-sm overflow-y-auto flex flex-col items-center justify-center relative bg-[url('https://www.transparenttextures.com/patterns/graphy.png')]">

        {sourceImage && activeTab !== AIJobType.TEXT_TO_IMAGE && !resultImage && (
             <img src={sourceImage} alt="Source" className="max-h-full max-w-full object-contain shadow-md rounded" />
        )}

        {resultImage && (
          <div className="relative group">
            <img src={resultImage} alt="Result" className="max-h-[600px] max-w-full object-contain shadow-2xl rounded border-4 border-white" />
            <a 
              href={resultImage} 
              download="hatice-ceylan-ai-result.png"
              className="absolute bottom-4 right-4 bg-white text-arch-dark px-4 py-2 rounded shadow font-bold hover:bg-arch-sand opacity-0 group-hover:opacity-100 transition-opacity"
            >
              Download
            </a>
          </div>
        )}

        {!sourceImage && !resultImage && (
          <div className="text-center text-arch-clay opacity-50">
            <div className="text-6xl mb-4">❖</div>
            <p className="font-serif text-xl">Hatice Ceylan AI Workbench</p>
            <p className="font-sans text-sm mt-2">Select a tool and begin your creation.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AIStudio;

import React, { useState, useEffect } from 'react';
import { analyzeVoiceCommand } from '../services/geminiService';
import { AppMode } from '../types';

interface VoiceControlProps {
  onNavigate: (mode: AppMode) => void;
}

const VoiceControl: React.FC<VoiceControlProps> = ({ onNavigate }) => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [feedback, setFeedback] = useState('');

  const handleToggleListen = () => {
    if (isListening) return;

    // Type assertion for Web Speech API
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
      setFeedback("Browser not supported.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'tr-TR'; // Defaulting to Turkish based on app name, can be 'en-US'
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    setIsListening(true);
    setFeedback("Listening...");
    setTranscript("");

    recognition.onresult = async (event: any) => {
      const text = event.results[0][0].transcript;
      setTranscript(text);
      setFeedback("Analyzing...");

      const analysis = await analyzeVoiceCommand(text);

      if (analysis.action === 'NAVIGATE_MAP') onNavigate(AppMode.MAP_DRAWING);
      else if (analysis.action === 'NAVIGATE_PLAN') onNavigate(AppMode.EXCAVATION_PLANNING);
      else if (analysis.action === 'NAVIGATE_ARTIFACT') onNavigate(AppMode.ARTIFACT_ILLUSTRATION);
      else if (analysis.action === 'NAVIGATE_AI') onNavigate(AppMode.AI_STUDIO);
      else if (analysis.action === 'NAVIGATE_TRANSLATE') onNavigate(AppMode.TRANSLATION);

      setFeedback(analysis.action !== 'UNKNOWN' ? `Executed: ${analysis.action}` : "Command not recognized.");
      setIsListening(false);
    };

    recognition.onerror = (event: any) => {
      console.error("Speech error", event.error);
      setFeedback("Error listening.");
      setIsListening(false);
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    recognition.start();
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      <div className={`transition-all duration-300 transform ${isListening ? 'scale-110' : 'scale-100'}`}>
        <button
          onClick={handleToggleListen}
          className={`
            w-16 h-16 rounded-full shadow-2xl flex items-center justify-center text-2xl
            ${isListening ? 'bg-red-600 animate-pulse text-white' : 'bg-arch-dark text-arch-sand hover:bg-black'}
          `}
        >
          {isListening ? '●' : '🎤'}
        </button>
      </div>
      {feedback && (
        <div className="absolute bottom-20 right-0 bg-black/80 text-white text-xs px-3 py-2 rounded whitespace-nowrap backdrop-blur-sm">
          {transcript && <div className="italic text-gray-300">"{transcript}"</div>}
          <div className="font-bold text-arch-sand">{feedback}</div>
        </div>
      )}
    </div>
  );
};

export default VoiceControl;

import React, { useState } from 'react';
import { translateDescription } from '../services/geminiService';

const Translator: React.FC = () => {
  const [input, setInput] = useState('');
  const [output, setOutput] = useState('');
  const [targetLang, setTargetLang] = useState('English');
  const [loading, setLoading] = useState(false);

  const handleTranslate = async () => {
    if (!input) return;
    setLoading(true);
    const res = await translateDescription(input, targetLang);
    setOutput(res);
    setLoading(false);
  };

  return (
    <div className="flex flex-col items-center justify-center h-full p-12 bg-arch-paper">
      <div className="max-w-4xl w-full grid grid-cols-2 gap-8">

        {/* Input */}
        <div className="flex flex-col gap-2">
          <label className="font-serif text-arch-dark font-bold text-lg">Original Text (Description)</label>
          <textarea 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            className="h-64 p-4 rounded-lg border-2 border-arch-sand bg-white focus:border-arch-clay outline-none resize-none font-serif text-lg leading-relaxed shadow-inner"
            placeholder="Enter artifact description or field notes..."
          />
        </div>

        {/* Output */}
        <div className="flex flex-col gap-2 relative">
          <div className="flex justify-between items-center">
            <label className="font-serif text-arch-dark font-bold text-lg">Translation</label>
            <select 
              value={targetLang}
              onChange={(e) => setTargetLang(e.target.value)}
              className="bg-white border border-arch-clay rounded px-2 py-1 text-sm focus:outline-none"
            >
              <option value="English">English</option>
              <option value="Turkish">Turkish</option>
              <option value="German">German</option>
              <option value="French">French</option>
              <option value="Italian">Italian</option>
            </select>
          </div>

          <div className="h-64 p-4 rounded-lg border-2 border-arch-sand bg-stone-50 overflow-y-auto font-serif text-lg leading-relaxed italic text-gray-700 shadow-sm relative">
            {loading ? (
                <div className="absolute inset-0 flex items-center justify-center text-arch-clay animate-pulse">Translating...</div>
            ) : output || <span className="text-gray-400">Translation will appear here...</span>}
          </div>
        </div>

      </div>

      <button 
        onClick={handleTranslate}
        disabled={loading}
