import React, { useRef, useState, useEffect } from 'react';
import { DrawingTool, AppMode } from '../types';

interface WorkBenchProps {
  mode: AppMode;
}

const WorkBench: React.FC<WorkBenchProps> = ({ mode }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [context, setContext] = useState<CanvasRenderingContext2D | null>(null);

  // Tool State
  const [color, setColor] = useState('#2b2b2b');
  const [lineWidth, setLineWidth] = useState(2);
  const [showGrid, setShowGrid] = useState(mode === AppMode.EXCAVATION_PLANNING);

  useEffect(() => {
    if (canvasRef.current) {
      const canvas = canvasRef.current;
      // High DPI fix
      const dpr = window.devicePixelRatio || 1;
      const rect = canvas.getBoundingClientRect();

      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;

      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.scale(dpr, dpr);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        setContext(ctx);

        // Initial Background
        ctx.fillStyle = '#fdfbf7';
        ctx.fillRect(0, 0, rect.width, rect.height);

        if (showGrid) drawGrid(ctx, rect.width, rect.height);
      }
    }
  }, [mode, showGrid]);

  useEffect(() => {
    setShowGrid(mode === AppMode.EXCAVATION_PLANNING);
  }, [mode]);

  const drawGrid = (ctx: CanvasRenderingContext2D, w: number, h: number) => {
    ctx.strokeStyle = '#e6dec8';
    ctx.lineWidth = 1;
    const step = 40;

    ctx.beginPath();
    for (let x = 0; x <= w; x += step) {
      ctx.moveTo(x, 0);
      ctx.lineTo(x, h);
    }
    for (let y = 0; y <= h; y += step) {
      ctx.moveTo(0, y);
      ctx.lineTo(w, y);
    }
    ctx.stroke();
  };

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!context) return;
    setIsDrawing(true);
    const { offsetX, offsetY } = e.nativeEvent;
    context.beginPath();
    context.moveTo(offsetX, offsetY);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || !context) return;
    const { offsetX, offsetY } = e.nativeEvent;

    context.strokeStyle = color;
    context.lineWidth = lineWidth;
    context.lineTo(offsetX, offsetY);
    context.stroke();
  };

  const stopDrawing = () => {
    if (!context) return;
    context.closePath();
    setIsDrawing(false);
  };

  const clearCanvas = () => {
    if (!context || !canvasRef.current) return;
    const canvas = canvasRef.current;
    // Clearing resets the pixel ratio transform, so we fill rect logic
    context.clearRect(0, 0, canvas.width, canvas.height); // Logical coords might be off if not careful
    // Safest simple clear
    const rect = canvas.getBoundingClientRect();
    context.fillStyle = '#fdfbf7';
    context.fillRect(0, 0, rect.width, rect.height);
    if (showGrid) drawGrid(context, rect.width, rect.height);
  };

  const downloadDrawing = () => {
    if (canvasRef.current) {
      const link = document.createElement('a');
      link.download = `hatice-ceylan-${mode.toLowerCase()}-${Date.now()}.png`;
      link.href = canvasRef.current.toDataURL();
      link.click();
    }
  };

  return (
    <div className="flex flex-col h-full w-full bg-arch-paper relative shadow-inner">
      {/* Toolbar */}
      <div className="absolute top-4 left-4 z-10 flex flex-col gap-2 bg-white/90 backdrop-blur p-3 rounded-lg border border-arch-clay shadow-sm">
        <label className="text-xs font-serif font-bold text-arch-dark uppercase mb-1">Araçlar</label>

        <div className="flex gap-2 mb-2">
          <button 
            onClick={() => setColor('#2b2b2b')} 
            className={`w-6 h-6 rounded-full border border-gray-300 ${color === '#2b2b2b' ? 'ring-2 ring-arch-clay' : ''}`}
            style={{ backgroundColor: '#2b2b2b' }}
            title="Siyah Mürekkep"
          />
          <button 
            onClick={() => setColor('#a67c52')} 
            className={`w-6 h-6 rounded-full border border-gray-300 ${color === '#a67c52' ? 'ring-2 ring-arch-clay' : ''}`}
            style={{ backgroundColor: '#a67c52' }}
            title="Kil Rengi"
          />
          <button 
            onClick={() => setColor('#b91c1c')} 
            className={`w-6 h-6 rounded-full border border-gray-300 ${color === '#b91c1c' ? 'ring-2 ring-arch-clay' : ''}`}
            style={{ backgroundColor: '#b91c1c' }}
            title="Kırmızı İşaretleyici"
          />
        </div>

        <div className="flex flex-col gap-1">
          <label className="text-[10px] text-arch-dark">Kalınlık</label>
          <input 
            type="range" 
            min="1" 
            max="10" 
            value={lineWidth} 
            onChange={(e) => setLineWidth(Number(e.target.value))}
            className="w-24 accent-arch-clay" 
          />
        </div>

        <div className="h-px bg-arch-sand my-1"></div>

        <button 
          onClick={() => setShowGrid(!showGrid)}
          className="text-xs flex items-center gap-2 hover:text-arch-clay transition-colors"
        >
          <span className="font-bold">#</span> Izgara
        </button>

        <button 
          onClick={clearCanvas}
          className="text-xs flex items-center gap-2 text-red-700 hover:text-red-900 transition-colors mt-2"
        >
          <span>✕</span> Temizle
        </button>

        <button 
          onClick={downloadDrawing}
          className="text-xs flex items-center gap-2 text-arch-clay hover:text-arch-dark transition-colors mt-1 font-bold"
        >
          <span>↓</span> İndir
        </button>
      </div>

      {/* Canvas Area */}
      <div className="flex-1 overflow-hidden p-8 cursor-crosshair">
         <div className="w-full h-full bg-white shadow-lg border border-arch-sand relative">
            <canvas
              ref={canvasRef}
              className="w-full h-full block"
              onMouseDown={startDrawing}
              onMouseMove={draw}
              onMouseUp={stopDrawing}
              onMouseLeave={stopDrawing}
            />

            {/* Corner Label */}
            <div className="absolute bottom-4 right-4 text-arch-clay font-hand text-2xl opacity-50 select-none pointer-events-none">
              {mode === AppMode.MAP_DRAWING ? 'Harita / Map' : 
               mode === AppMode.EXCAVATION_PLANNING ? 'Plan / Plan' : 
               'Buluntu / Artifact'}
            </div>
         </div>
      </div>
    </div>
  );
};

