import React, { useState, useEffect, useRef } from 'react';

const Profile: React.FC = () => {
  const [profileImage, setProfileImage] = useState<string>('https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=400&auto=format&fit=crop');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Yerel depolamadan fotoğrafı yükle
  useEffect(() => {
    const savedImage = localStorage.getItem('hc_profile_image');
    if (savedImage) {
      setProfileImage(savedImage);
    }
  }, []);

  const handleImageClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert("Dosya boyutu çok büyük (Maksimum 2MB).");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        setProfileImage(base64String);
        localStorage.setItem('hc_profile_image', base64String);
        // Dispatch event to sync with App header
        window.dispatchEvent(new Event('profileImageUpdated'));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeProfileImage = () => {
    if (window.confirm("Profil fotoğrafını kaldırmak istediğinize emin misiniz?")) {
      const defaultImg = 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=400&auto=format&fit=crop';
      setProfileImage(defaultImg);
      localStorage.removeItem('hc_profile_image');
      window.dispatchEvent(new Event('profileImageUpdated'));
    }
  };

  return (
    <div className="flex flex-col h-full bg-arch-paper overflow-y-auto p-8 space-y-8">
      {/* Profile ID Card Section */}
      <div className="max-w-4xl mx-auto w-full flex flex-col md:flex-row bg-white border-2 border-arch-clay shadow-2xl rounded-lg overflow-hidden transform -rotate-1">
        {/* Photo and Seal */}
        <div className="w-full md:w-64 bg-arch-sand p-6 flex flex-col items-center border-b md:border-b-0 md:border-r border-arch-clay relative">

          {/* Gold Leaf Frame for Photo */}
          <div className="gold-leaf-border mb-4">
            <div 
              onClick={handleImageClick}
              className="w-40 h-48 bg-stone-300 shadow-inner relative overflow-hidden grayscale hover:grayscale-0 transition-all cursor-pointer group"
            >
              <img 
                src={profileImage} 
                alt="Profil" 
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                <span className="text-white text-[10px] font-bold uppercase tracking-widest px-2 text-center">Değiştir</span>
              </div>

              {/* Ornate corner accents */}
              <div className="ornate-corner corner-tl"></div>
              <div className="ornate-corner corner-tr"></div>
              <div className="ornate-corner corner-bl"></div>
              <div className="ornate-corner corner-br"></div>
            </div>
          </div>

          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            className="hidden" 
          />

          <div className="absolute top-2 right-2 opacity-20 transform rotate-12 pointer-events-none">
            <div className="w-20 h-20 border-4 border-arch-clay rounded-full flex items-center justify-center font-serif font-bold text-xs text-center uppercase p-2 leading-tight">
              Kültür & Sanat Arşivi
            </div>
          </div>
